'use client';

import Link from 'next/link';
import { useEffect, useState } from 'react';
import {
  addSection,
  InstructorCourse,
  listMyInstructorCourses,
  publishCourse,
  uploadLectureVideo,
} from '@/lib/client-api';

export default function InstructorCoursesPage() {
  const [courses, setCourses] = useState<InstructorCourse[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [sectionTitle, setSectionTitle] = useState<Record<string, string>>({});
  const [lectureTitle, setLectureTitle] = useState<Record<string, string>>({});
  const [lectureFile, setLectureFile] = useState<Record<string, File | null>>({});
  const [busySectionId, setBusySectionId] = useState<string | null>(null);

  async function loadCourses() {
    try {
      const data = await listMyInstructorCourses();
      setCourses(data);
      setError(null);
    } catch {
      setError('Please login as instructor to view your courses.');
    }
  }

  useEffect(() => {
    void loadCourses();
  }, []);

  return (
    <main className="mx-auto max-w-6xl px-6 py-12">
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Instructor dashboard</h1>
          <p className="mt-1 text-slate-600">Manage course content and publish your products.</p>
        </div>
        <Link href="/instructor/courses/new" className="rounded-md bg-slate-900 px-4 py-2 text-sm font-semibold text-white">
          + New course
        </Link>
      </div>

      {error && <p className="mb-4 rounded-md bg-red-50 px-3 py-2 text-sm text-red-700">{error}</p>}

      <div className="space-y-4">
        {courses.map((course) => (
          <article key={course.id} className="rounded-xl border border-slate-200 bg-white p-5 shadow-sm">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <h2 className="text-xl font-semibold text-slate-900">{course.title}</h2>
                <p className="mt-1 text-sm text-slate-600">/{course.slug}</p>
                <p className="mt-2 text-sm text-slate-600">{course.description}</p>
              </div>
              <div className="flex items-center gap-2">
                <Link
                  href={`/instructor/courses/${course.id}/edit`}
                  className="rounded-md border border-slate-300 px-3 py-1.5 text-sm font-semibold"
                >
                  Edit
                </Link>
                <span className={`rounded-full px-3 py-1 text-xs font-semibold ${course.isPublished ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                  {course.isPublished ? 'Published' : 'Draft'}
                </span>
                {!course.isPublished && (
                  <button
                    type="button"
                    onClick={async () => {
                      await publishCourse(course.id);
                      await loadCourses();
                    }}
                    className="rounded-md border border-slate-300 px-3 py-1.5 text-sm font-semibold"
                  >
                    Publish
                  </button>
                )}
              </div>
            </div>

            <div className="mt-4 flex flex-wrap gap-2">
              <input
                value={sectionTitle[course.id] ?? ''}
                onChange={(event) =>
                  setSectionTitle((prev) => ({ ...prev, [course.id]: event.target.value }))
                }
                placeholder="Add section title"
                className="min-w-[240px] rounded-md border border-slate-300 px-3 py-2 text-sm"
              />
              <button
                type="button"
                onClick={async () => {
                  const title = sectionTitle[course.id];
                  if (!title) return;
                  await addSection(course.id, { title });
                  setSectionTitle((prev) => ({ ...prev, [course.id]: '' }));
                }}
                className="rounded-md bg-violet-600 px-3 py-2 text-sm font-semibold text-white"
              >
                Add section
              </button>
            </div>

            <div className="mt-5 space-y-4">
              {(course.sections ?? []).map((section) => (
                <div key={section.id} className="rounded-lg border border-slate-200 p-4">
                  <div className="flex flex-wrap items-center justify-between gap-2">
                    <p className="font-semibold text-slate-900">
                      Section {section.position}: {section.title}
                    </p>
                    <span className="text-xs text-slate-500">
                      {(section.lectures ?? []).length} lecture(s)
                    </span>
                  </div>

                  <ul className="mt-3 space-y-2">
                    {(section.lectures ?? []).map((lecture) => (
                      <li key={lecture.id} className="rounded-md bg-slate-50 px-3 py-2 text-sm">
                        <div className="flex flex-wrap items-center justify-between gap-2">
                          <span>
                            #{lecture.position} {lecture.title}
                          </span>
                          <a
                            href={lecture.videoUrl ?? undefined}
                            target="_blank"
                            rel="noreferrer"
                            className="font-semibold text-violet-700"
                          >
                            Open video
                          </a>
                        </div>
                      </li>
                    ))}
                    {(section.lectures ?? []).length === 0 && (
                      <li className="text-sm text-slate-500">No lecture videos uploaded yet.</li>
                    )}
                  </ul>

                  <div className="mt-3 grid gap-2 md:grid-cols-[1fr_1fr_auto]">
                    <input
                      value={lectureTitle[section.id] ?? ''}
                      onChange={(event) =>
                        setLectureTitle((prev) => ({
                          ...prev,
                          [section.id]: event.target.value,
                        }))
                      }
                      placeholder="Lecture title"
                      className="rounded-md border border-slate-300 px-3 py-2 text-sm"
                    />
                    <input
                      type="file"
                      accept="video/*"
                      onChange={(event) => {
                        const file = event.target.files?.[0] ?? null;
                        setLectureFile((prev) => ({ ...prev, [section.id]: file }));
                      }}
                      className="rounded-md border border-slate-300 px-3 py-2 text-sm"
                    />
                    <button
                      type="button"
                      disabled={busySectionId === section.id}
                      onClick={async () => {
                        const title = lectureTitle[section.id];
                        const video = lectureFile[section.id];
                        if (!title || !video) return;

                        try {
                          setBusySectionId(section.id);
                          await uploadLectureVideo({
                            courseId: course.id,
                            sectionId: section.id,
                            title,
                            video,
                          });

                          setLectureTitle((prev) => ({ ...prev, [section.id]: '' }));
                          setLectureFile((prev) => ({ ...prev, [section.id]: null }));
                          await loadCourses();
                        } finally {
                          setBusySectionId(null);
                        }
                      }}
                      className="rounded-md bg-slate-900 px-3 py-2 text-sm font-semibold text-white disabled:opacity-50"
                    >
                      {busySectionId === section.id ? 'Uploading...' : 'Upload video'}
                    </button>
                  </div>
                </div>
              ))}
              {(course.sections ?? []).length === 0 && (
                <p className="text-sm text-slate-500">
                  Add a section first, then upload lecture videos against that topic.
                </p>
              )}
            </div>
          </article>
        ))}

        {courses.length === 0 && !error && (
          <div className="rounded-xl border border-dashed border-slate-300 bg-white p-8 text-center text-slate-600">
            No courses yet. Create your first course.
          </div>
        )}
      </div>
    </main>
  );
}
